import{_ as r,a as o,b as a}from"./chunks/hub0080-channel-edit-basic.BmNb4UH4.js";import{_ as d,c as n,o as s,ag as e}from"./chunks/framework.XjE0kKti.js";const g="/gatewayweb/docs/assets/hub0080-template-select.D-vWracZ.png",h="/gatewayweb/docs/assets/hub0080-channel-edit-config.Itu5nmOk.png",f=JSON.parse('{"title":"预警服务配置（hub0080）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0080.md","filePath":"modules/hub0080.md","lastUpdated":1776841524000}'),l={name:"modules/hub0080.md"};function b(i,t,c,p,u,m){return s(),n("div",null,[...t[0]||(t[0]=[e('<h1 id="预警服务配置-hub0080" tabindex="-1">预警服务配置（hub0080） <a class="header-anchor" href="#预警服务配置-hub0080" aria-label="Permalink to &quot;预警服务配置（hub0080）&quot;">​</a></h1><p>维护告警<strong>渠道</strong>（邮件、QQ、企业微信、钉钉、Webhook、短信等）的连接参数、发送策略与默认模板，供预警引擎在发送通知时选用。列表中可查看发送统计、快速启停渠道，并支持重载配置、设为默认、复制渠道与预警测试。</p><p><img src="'+r+'" alt="渠道列表与筛选"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>渠道 CRUD</td><td><strong>新增 / 编辑 / 查看</strong> 使用弹窗表单；<strong>删除</strong> 入口存在，当前前端在确认后会提示能力尚未接入（以界面提示为准）。</td></tr><tr><td>启停</td><td>列表「启用状态」列内 <strong>开关</strong> 直接切换，会调用更新接口写回 <code>activeFlag</code>。</td></tr><tr><td>默认渠道</td><td>将某一渠道设为未指定渠道时的默认出口。</td></tr><tr><td>重载配置</td><td>使内存/缓存侧配置与存储一致并尽快生效。</td></tr><tr><td>预警测试</td><td>对已启用渠道发起一次测试投递（弹窗内可编辑测试内容）。</td></tr><tr><td>复制</td><td>基于现有渠道快速新建一条配置（需重新填写 <strong>渠道名称</strong>）。</td></tr></tbody></table><p>与 <strong><a href="./hub0040.html">服务中心实例（hub0040）</a></strong> 告警配置中的「渠道名称」对应：实例侧填写的是此处维护的渠道名称。</p><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>预警管理</strong> → <strong>预警服务配置</strong>。</p><hr><h2 id="列表与筛选" tabindex="-1">列表与筛选 <a class="header-anchor" href="#列表与筛选" aria-label="Permalink to &quot;列表与筛选&quot;">​</a></h2><h3 id="筛选项" tabindex="-1">筛选项 <a class="header-anchor" href="#筛选项" aria-label="Permalink to &quot;筛选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>渠道名称</strong></td><td>精确匹配查询（占位：请输入渠道名称）。</td></tr><tr><td><strong>渠道类型</strong></td><td>全部 / 邮件 / QQ / 企业微信 / 钉钉 / Webhook / 短信。</td></tr><tr><td><strong>启用状态</strong></td><td>全部 / 启用 / 禁用。</td></tr><tr><td><strong>默认渠道</strong></td><td>全部 / 是 / 否。</td></tr></tbody></table><p>使用 <strong>查询</strong> 刷新列表，<strong>重置</strong> 清空条件。</p><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新增渠道</strong></td><td>打开「新增告警渠道配置」弹窗。</td></tr><tr><td><strong>删除</strong></td><td>需先在表格中 <strong>单击</strong> 一行使其成为当前高亮行，再点删除；未选中行时会提示先点击选择。删除确认后，若后端未开放接口，界面会提示 <strong>删除功能暂未实现</strong>（与当前前端实现一致）。</td></tr><tr><td><strong>查询 / 重置</strong></td><td>与筛选区一致。</td></tr></tbody></table><h3 id="表格列说明" tabindex="-1">表格列说明 <a class="header-anchor" href="#表格列说明" aria-label="Permalink to &quot;表格列说明&quot;">​</a></h3><p>常见列包括：<strong>渠道名称</strong>、<strong>渠道类型</strong>（彩色标签）、<strong>渠道描述</strong>、<strong>优先级</strong>（1～10，<strong>数字越小优先级越高</strong>）、<strong>默认渠道</strong>（是/否）、<strong>启用状态</strong>（行内开关）、<strong>总发送数 / 成功数 / 失败数</strong>、<strong>最后发送时间</strong>、创建与修改时间等。</p><hr><h2 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h2><p><img src="'+o+'" alt="渠道行右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制行数据 / 复制单元格</strong></td><td>表格通用能力。</td></tr><tr><td><strong>查看详情</strong></td><td>只读打开「查看告警渠道配置详情」。</td></tr><tr><td><strong>编辑</strong></td><td>打开「编辑告警渠道配置」。</td></tr><tr><td><strong>复制</strong></td><td>以当前渠道为模板进入 <strong>新增</strong> 流程，<strong>渠道名称</strong> 清空，需填写新名称后保存。</td></tr><tr><td><strong>重载配置</strong></td><td>确认后调用重载接口并刷新列表展示。</td></tr><tr><td><strong>设为默认</strong></td><td>若已是默认渠道会提示无需重复设置；否则二次确认后设为默认。</td></tr><tr><td><strong>预警测试</strong></td><td>仅 <strong>已启用</strong> 的渠道可测；未启用会提示无法测试。</td></tr><tr><td><strong>删除</strong></td><td>与工具栏删除逻辑相同（含「暂未实现」提示，以后端接入为准）。</td></tr></tbody></table><hr><h2 id="新增-编辑-查看弹窗" tabindex="-1">新增 / 编辑 / 查看弹窗 <a class="header-anchor" href="#新增-编辑-查看弹窗" aria-label="Permalink to &quot;新增 / 编辑 / 查看弹窗&quot;">​</a></h2><p>标题分别为：<strong>新增告警渠道配置</strong>、<strong>编辑告警渠道配置</strong>、<strong>查看告警渠道配置详情</strong>。支持最大化与关闭；查看模式提交即关闭，不调用保存接口。</p><h3 id="tab-基本信息" tabindex="-1">Tab：基本信息 <a class="header-anchor" href="#tab-基本信息" aria-label="Permalink to &quot;Tab：基本信息&quot;">​</a></h3><p><img src="'+a+'" alt="基本信息 Tab"></p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>渠道名称</strong></td><td>必填；英文、数字、下划线，最长 32 字符，作为主键展示在列表中。</td></tr><tr><td><strong>渠道类型</strong></td><td>必填；决定「渠道配置」Tab 下展示哪些分组（见下节）。</td></tr><tr><td><strong>渠道描述</strong></td><td>可选，最多约 500 字（以界面计数为准）。</td></tr><tr><td><strong>优先级</strong></td><td>必填，1～10。</td></tr><tr><td><strong>默认渠道</strong></td><td>是否作为未指定渠道时的默认路由。</td></tr><tr><td><strong>启用状态</strong></td><td>开关；禁用后该渠道不会被调度，且无法进行 <strong>预警测试</strong>。</td></tr><tr><td><strong>默认模板名称</strong></td><td>可输入或点击 <strong>「…」</strong> 打开模板选择窗口；列表会按当前 <strong>渠道类型</strong> 过滤可选模板（与 <strong><a href="./hub0081.html">预警模板管理（hub0081）</a></strong> 中数据对应）。</td></tr></tbody></table><p><img src="'+g+'" alt="选择模板"></p><hr><h3 id="tab-渠道配置" tabindex="-1">Tab：渠道配置 <a class="header-anchor" href="#tab-渠道配置" aria-label="Permalink to &quot;Tab：渠道配置&quot;">​</a></h3><p>按 <strong>渠道类型</strong> 动态展示 <strong>服务器配置</strong>、<strong>发送配置</strong> 等分组；下方 <strong>通用配置</strong> 对各类型均可见（消息内容格式、超时、重试、异步发送等）。</p><p><strong>企业微信</strong> 示例（与代码字段一致）：</p><p><img src="'+h+'" alt="渠道配置 Tab（企业微信示例）"></p><table tabindex="0"><thead><tr><th>分组</th><th>典型字段</th></tr></thead><tbody><tr><td>服务器配置（企业微信）</td><td>Webhook 地址（必填）、签名密钥（可选）、消息类型（文本 / Markdown）、超时时间（秒）。</td></tr><tr><td>发送配置（企业微信）</td><td>@成员 userid 列表、@成员手机号列表（多值逗号分隔，可选）。</td></tr><tr><td>通用配置</td><td>消息内容格式（文本 / HTML / Markdown）、超时时间（秒）、重试次数、重试间隔（秒）、是否异步发送。</td></tr></tbody></table><p><strong>邮件</strong>：SMTP 地址、端口、用户名、密码、发件人、TLS、收件人/抄送/密送等。</p><p><strong>QQ</strong>：Webhook 地址、签名密钥、@所有人、@指定用户等。</p><p><strong>钉钉 / Webhook / 短信</strong>：若界面仅展示「通用配置」而无独立服务器分组，请以当前版本界面为准；后续版本可能扩展表单项。</p><hr><h3 id="tab-其他信息" tabindex="-1">Tab：其他信息 <a class="header-anchor" href="#tab-其他信息" aria-label="Permalink to &quot;Tab：其他信息&quot;">​</a></h3><p>备注及创建人、创建时间、修改人、修改时间（多为只读）。</p><hr><h2 id="预警测试" tabindex="-1">预警测试 <a class="header-anchor" href="#预警测试" aria-label="Permalink to &quot;预警测试&quot;">​</a></h2><p>在渠道已 <strong>启用</strong> 的前提下，通过右键 <strong>预警测试</strong> 打开测试弹窗，可查看或微调测试标题与正文，提交后由后端向该渠道投递一条测试消息。失败时请关注接口返回的错误信息。</p><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ol><li>先配置好 <strong>渠道配置</strong> Tab 中的连接参数，保存后再做 <strong>预警测试</strong>，避免无效重试。</li><li>多渠道并存时，用 <strong>优先级</strong> 与 <strong>默认渠道</strong> 约定主备出口。</li><li>修改 Webhook 或 SMTP 密码后建议执行 <strong>重载配置</strong>，并观察 <strong>成功数 / 失败数</strong> 是否异常增长。</li><li>模板正文与变量由 <strong><a href="./hub0081.html">hub0081</a></strong> 维护；此处仅绑定 <strong>默认模板名称</strong>。</li></ol>',48)])])}const k=d(l,[["render",b]]);export{f as __pageData,k as default};
